 48	
 49	function buildCrc32Table() {
 50	  const table = new Uint32Array(256);
 51	
 52	  for (let index = 0; index < table.length; index += 1) {
 53	    let value = index;
 54	
 55	    for (let bit = 0; bit < 8; bit += 1) {
 56	      value = (value & 1) === 0 ? value >>> 1 : (value >>> 1) ^ 0xedb88320;
 57	    }
 58	
 59	    table[index] = value >>> 0;
 60	  }
 61	
 62	  return table;
 63	}
 64	
 65	function computeCrc32(bytes: Uint8Array) {
 66	  let crc = 0xffffffff;
 67	
 68	  for (const byte of bytes) {
 69	    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
 70	  }
 71	
 72	  return (crc ^ 0xffffffff) >>> 0;
 73	}
 74	
 75	function decodeBase32(input: string) {
 76	  const output: number[] = [];
 77	  let buffer = 0;
 78	  let bits = 0;
 79	
 80	  for (const character of input) {
 81	    const value = BASE32_ALPHABET.indexOf(character);
 82	
 83	    if (value === -1) {
 84	      return null;
 85	    }
 86	
 87	    buffer = (buffer << 5) | value;
 88	    bits += 5;
 89	
 90	    while (bits >= 8) {
 91	      bits -= 8;
 92	      output.push((buffer >>> bits) & 0xff);
 93	    }
 94	  }
 95	
 96	  if (bits > 0 && (buffer & ((1 << bits) - 1)) !== 0) {
 97	    return null;
 98	  }
 99	
100	  return Uint8Array.from(output);
101	}
102	
103	function isValidCanisterId(value: string) {
104	  if (!/^[a-z2-7-]+$/.test(value)) {
105	    return false;
106	  }
107	
108	  const groups = value.split("-");
109	  if (groups.length === 0 || groups.some((group) => group.length === 0 || group.length > 5)) {
110	    return false;
111	  }
112	
113	  if (groups.slice(0, -1).some((group) => group.length !== 5)) {
114	    return false;
115	  }
116	
117	  const decoded = decodeBase32(groups.join(""));
118	  if (decoded === null || decoded.length < 4) {
119	    return false;
120	  }
121	
122	  const checksum =
123	    (decoded[0] << 24) | (decoded[1] << 16) | (decoded[2] << 8) | decoded[3];
124	  const principal = decoded.slice(4);
125	
126	  return (checksum >>> 0) === computeCrc32(principal);
127	}
