129	function validateTargetConfig(config: IndexerTargetConfig) {
130	  const errors: string[] = [];
131	
132	  if (!Array.isArray(config.canisterIds) || config.canisterIds.length === 0) {
133	    errors.push("Indexer ingestion config must include at least one canister ID.");
134	  }
135	
136	  for (const [index, canisterId] of config.canisterIds.entries()) {
137	    if (typeof canisterId !== "string" || !isValidCanisterId(canisterId.trim())) {
138	      errors.push(
139	        `Indexer ingestion config canisterIds[${index}] must be a valid canister ID. Received: ${JSON.stringify(canisterId)}.`
140	      );
141	    }
142	  }
143	
144	  if (!INDEXER_NETWORK_TARGETS.includes(config.network.target)) {
145	    errors.push(
