157	    if (!Number.isInteger(config.network.local.port) || config.network.local.port <= 0) {
158	      errors.push(
159	        'Indexer ingestion config network.local.port must be set to a positive integer when network.target is "local".'
160	      );
161	    }
162	  }
163	
164	  if (errors.length > 0) {
165	    throw new Error(`Invalid indexer ingestion config:\n- ${errors.join("\n- ")}`);
166	  }
167	}
